// - String: "\"Alice\""
// - Number: "42"
// - Object: "{\"key\": \"value\"}"
// - Array: "[1, 2, 3]"
// - Boolean: "true"
// - Null: "null"
//
// Examples:
//
//	{ op: ADD, path: "/address/city", value: "\"NYC\"" }
//	{ op: REMOVE, path: "/oldField" }
//	{ op: REPLACE, path: "/quantity", value: "100" }
